//ret = texture(sampler_main, vUv);
re = texture( MilkDrop3_001, my_uv);
re = mix( texture(sampler_MilkDrop3_002,my_uv), re, ret.x);
ret = mix( re, 1-re, ret.y);


  fragColor = ret;
